// The milestone-2 scene from C#, on the kaya bindings: KayaWire.cs
// (generated by kaya-bindgen from kaya::spec) carries the packers and
// parser, Kaya.cs the P/Invoke and the direct-ring occurrence loop.
// What remains here is the scene declaration and the logic answering
// occurrences.
//
// Build the library first (cargo build / cargo xwin build --release),
// keep kaya.dll on PATH or set KAYA_LIB, then: dotnet run

using System.Collections.Generic;
using System.Threading;

static class Program
{
    // Guest-allocated ids, counted from 1 per space.
    const ulong SigStatus = 1;
    const ulong SigExtras = 2;
    const ulong WColumn = 1;
    const ulong WStep = 2;
    const ulong WStatus = 3;
    const ulong WWhen = 4;
    const ulong WGroups = 5;
    const ulong CGroups = 1;
    const ulong CItems = 2;
    const ulong NBanner = 1;
    const ulong NGroupCol = 2;
    const ulong NGroupLbl = 3;
    const ulong NItemsFor = 4;
    const ulong NItemRow = 5;
    const ulong NItemText = 6;
    const ulong NRemove = 7;

    static void BuildScene()
    {
        Kaya.Submit(
            KayaWire.TxCreateSignal(SigStatus, "step 0"),
            KayaWire.TxCreateSignal(SigExtras, false),
            KayaWire.TxCreateWidget(WColumn, KayaWire.KindColumn),
            KayaWire.TxCreateWidget(WStep, KayaWire.KindButton),
            KayaWire.TxSetText(WStep, "step"),
            KayaWire.TxCreateWidget(WStatus, KayaWire.KindLabel),
            KayaWire.TxBindText(WStatus, SigStatus),
            // When(extras): a banner label.
            KayaWire.TxCreateWhen(WWhen, SigExtras),
            KayaWire.TxCreateWidget(NBanner, KayaWire.KindLabel),
            KayaWire.TxSetText(NBanner, "extras on"),
            KayaWire.TxTemplateEnd(),
            // For over groups, nesting a For over items.
            KayaWire.TxCreateCollection(CGroups),
            KayaWire.TxCreateFor(WGroups, CGroups),
            KayaWire.TxCreateWidget(NGroupCol, KayaWire.KindColumn),
            KayaWire.TxCreateWidget(NGroupLbl, KayaWire.KindLabel),
            KayaWire.TxBindTextElement(NGroupLbl),
            KayaWire.TxAddChild(NGroupCol, NGroupLbl),
            KayaWire.TxCreateCollection(CItems),
            KayaWire.TxCreateFor(NItemsFor, CItems),
            KayaWire.TxCreateWidget(NItemRow, KayaWire.KindColumn),
            KayaWire.TxCreateWidget(NItemText, KayaWire.KindLabel),
            KayaWire.TxBindTextElement(NItemText),
            KayaWire.TxCreateWidget(NRemove, KayaWire.KindButton),
            KayaWire.TxSetText(NRemove, "remove"),
            KayaWire.TxAddChild(NItemRow, NItemText),
            KayaWire.TxAddChild(NItemRow, NRemove),
            KayaWire.TxTemplateEnd(),
            KayaWire.TxAddChild(NGroupCol, NItemsFor),
            KayaWire.TxTemplateEnd(),
            KayaWire.TxAddChild(WColumn, WStep),
            KayaWire.TxAddChild(WColumn, WStatus),
            KayaWire.TxAddChild(WColumn, WWhen),
            KayaWire.TxAddChild(WColumn, WGroups),
            KayaWire.TxMount(0, WColumn)); // window 0: the default
    }

    static void App()
    {
        BuildScene();
        int steps = 0;
        while (Kaya.NextClick(out ulong id, out List<object> keys))
        {
            if (keys.Count == 0 && id == WStep)
            {
                steps++;
                var tx = new List<byte[]>();
                if (steps == 1)
                {
                    tx.Add(KayaWire.TxCollectionInsert(CGroups, null, "g1", "Work"));
                    tx.Add(KayaWire.TxCollectionInsert(CItems, new object[] { "g1" }, "a", "send report"));
                    tx.Add(KayaWire.TxCollectionInsert(CItems, new object[] { "g1" }, "b", "buy milk"));
                }
                else if (steps == 2)
                {
                    tx.Add(KayaWire.TxCollectionInsert(CGroups, null, "g2", "Home"));
                    tx.Add(KayaWire.TxCollectionInsert(CItems, new object[] { "g2" }, "a", "water plants"));
                    tx.Add(KayaWire.TxCollectionUpdate(CGroups, null, "g1", "Office"));
                }
                tx.Add(KayaWire.TxWriteSignal(SigExtras, steps == 1));
                tx.Add(KayaWire.TxWriteSignal(SigStatus, $"step {steps}"));
                Kaya.Submit(tx.ToArray());
            }
            else if (keys.Count == 2 && id == NRemove)
            {
                string group = (string)keys[0];
                string item = (string)keys[1];
                Kaya.Submit(
                    KayaWire.TxCollectionRemove(CItems, new object[] { group }, item),
                    KayaWire.TxWriteSignal(SigStatus, $"removed {group}/{item}"));
            }
        }
    }

    static void Main()
    {
        Kaya.Init();
        var appThread = new Thread(App);
        appThread.Start();
        int code = Kaya.Run(); // takes over the main thread until the app exits
        appThread.Join();      // shutdown has been signalled; the drain loop ends
        System.Environment.Exit(code);
    }
}
